update tb_product
set product_name = #{productName}, category_id = #{categoryId}, price = #{price},
    specification = #{specification}, product_image = #{productImage}, origin = #{origin},
    remark = #{remark}, stock_threshold = #{stockThreshold}, status = #{status}, supplier_id = #{supplierId}
where product_id = #{productId}

mapper.select:
select * from tb_product

    is_deleted = 0
    
        and product_name like concat('%', #{productName}, '%')
    
    
        and category_id = #{categoryId}
    
    
        and status = #{status}
    

order by create_time desc limit #{offset}, #{pageSize}

